def process_payment(user, cart_items, payment_details):
    role = str(user.get("role", "basic")).lower()
    discounts = {
        "basic": 0.0,
        "premium": 0.15,
        "enterprise": 0.30,
    }

    if role not in discounts:
        raise ValueError(f"Invalid user role: {role}")

    if not isinstance(cart_items, list) or not cart_items:
        raise ValueError("cart_items must be a non-empty list")

    subtotal = 0.0
    for item in cart_items:
        if not isinstance(item, dict):
            raise ValueError("Each cart item must be a dict")
        price = item.get("price")
        quantity = item.get("quantity", 1)
        if price is None:
            raise ValueError("Each cart item must include a price")
        if quantity is None:
            quantity = 1
        if quantity < 0:
            raise ValueError("Item quantity cannot be negative")
        subtotal += float(price) * int(quantity)

    discount_rate = discounts[role]
    discount_amount = subtotal * discount_rate
    total = subtotal - discount_amount

    if not isinstance(payment_details, dict) or not payment_details:
        raise ValueError("payment_details must be a non-empty dict")

    if "method" not in payment_details:
        raise ValueError("payment_details must include a method")

    payment_result = {
        "status": "success",
        "role": role,
        "subtotal": round(subtotal, 2),
        "discount_percentage": int(discount_rate * 100),
        "discount_amount": round(discount_amount, 2),
        "total": round(total, 2),
        "payment_method": payment_details.get("method"),
    }

    return payment_result